1	<script lang="ts">
2		// DotMeter v2, the judge's hand-built take, for direct iteration with Jake.
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live, to two decimals.
6	
7		// The two entries mean something: x is how loud, y is how fast.
8		const CANDIDATES = [
9			{ id: 'c1', name: 'Night Drive', angle: 20 },
10			{ id: 'c2', name: 'Glass Rain', angle: 70 },
11			{ id: 'c3', name: 'Slow Burn', angle: 110 },
12			{ id: 'c4', name: 'Static', angle: 160 }
13		];
14	
15		let challenge = $state<null | 'cheat' | 'short'>(null);
16		let solvedCheat = $state(false);
17		let solvedShort = $state(false);
18		const WHY = {
19			cheat:
20				'A song that is simply louder and faster everywhere piles up score without matching your mix. A raw meter overrates intense tracks, so a recommender built on it keeps pushing whatever is biggest.',
21			short:
22				'A quiet song that matches your mix exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed.'
23		};
24		function startChallenge(kind: 'cheat' | 'short') {
25			// one click always re-arms: a solved card resets on first click,
26			// whether or not another challenge was active in between
27			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
28			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
29			challenge = kind;
30			probeAngle = 40;
31			lengthC1 = 1.0;
32			selected = 'c1';
33		}
34		$effect(() => {
35			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
36			if (challenge === 'short' && shortChanged) solvedShort = true;
37		});
38	
39		let probeAngle = $state(40);
40		let lengthC1 = $state(1.0);
41		let selected = $state('c1');
42		let hovered = $state<string | null>(null);
43		let dragging = $state<'probe' | 'length' | null>(null);
44	
45		const rad = (d: number) => (d * Math.PI) / 180;
46		// The score readout everywhere on screen prints to one decimal; leadership
47		// must be judged at that SAME precision, or two songs that print the same
48		// number could have one silently crowned over the other.
49		const f1 = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(1);
50	
51		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
52	
53		const rows = $derived(
54			CANDIDATES.map((c) => {
55				const len = c.id === 'c1' ? lengthC1 : 1;
56				const x = len * Math.cos(rad(c.angle));
57				const y = len * Math.sin(rad(c.angle));
58				const px = probe.x * x; // the x-term product
59				const py = probe.y * y; // the y-term product
60				return { ...c, len, x, y, px, py, score: px + py };
61			})
62		);
63	
64		const maxDisp = $derived(Math.max(...rows.map((r) => parseFloat(f1(r.score)))));
65		const leaders = $derived(
66			rows.filter((r) => parseFloat(f1(r.score)) === maxDisp).map((r) => r.id)
67		);
68		const tied = $derived(leaders.length > 1);
69		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
70	
71		// The mirror lesson: c1 aims truest but is too short to win.
72		const shortChanged = $derived.by(() => {
73			const c1 = rows[0];
74			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
75			return rows.every(
76				(r) =>
77					r.id === 'c1' ||
78					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
79						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
80			);
81		});
82	
83		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
84		// Returns the most deserving victim (best-aligned beaten song) so the flag
85		// can name the exact pair instead of making a vague claim about the board.
86		const cheatVictim = $derived.by(() => {
87			const c1 = rows[0];
88			if (lengthC1 <= 1.05) return null;
89			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
90			const beaten = rows.filter(
91				(r) =>
92					r.id !== 'c1' &&
93					dist(r.angle) < dist(c1.angle) &&
94					parseFloat(f1(c1.score)) > parseFloat(f1(r.score))
95			);
96			if (beaten.length === 0) return null;
97			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
98		});
99		const cheatActive = $derived(cheatVictim !== null);
100		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
101	
102		// --- Arena geometry (SVG units) ---
103		const S = 400; // viewBox square
104		const CX = S / 2;
105		const CY = S / 2;
106		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
107		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
108	
109		function arrow(x: number, y: number) {
110			const tip = pt(x, y);
111			const ang = Math.atan2(CY - tip.py, tip.px - CX);
112			const L = Math.hypot(tip.px - CX, tip.py - CY);
113			const head = Math.max(7, Math.min(11, L * 0.09));
114			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
115			const left = {
116				px: back.px - head * 0.55 * Math.sin(ang),
117				py: back.py - head * 0.55 * Math.cos(ang)
118			};
119			const right = {
120				px: back.px + head * 0.55 * Math.sin(ang),
121				py: back.py + head * 0.55 * Math.cos(ang)
122			};
123			return {
124				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
125				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
126			};
127		}
128	
129		function labelPos(angle: number, len: number, pad = 20) {
130			const d = len * R + pad;
131			return { px: CX + d * Math.cos(rad(angle)), py: CY - d * Math.sin(rad(angle)) };
132		}
133	
134		let arenaEl = $state<SVGSVGElement | null>(null);
135	
136		function anglesFromEvent(e: PointerEvent) {
137			if (!arenaEl) return null;
138			const r = arenaEl.getBoundingClientRect();
139			const x = ((e.clientX - r.left) / r.width) * S - CX;
140			const y = CY - ((e.clientY - r.top) / r.height) * S;
141			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
142		}
143	
144		function onArenaPointer(e: PointerEvent) {
145			const a = anglesFromEvent(e);
146			if (!a || !dragging) return;
147			if (dragging === 'probe') probeAngle = Math.round(a.angle / 5) * 5 % 360;
148			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
149		}
150	
151		function startDrag(kind: 'probe' | 'length', e: PointerEvent) {
152			dragging = kind;
153			(e.currentTarget as Element).setPointerCapture(e.pointerId);
154		}
155	
156		function probeKeys(e: KeyboardEvent) {
157			let h = true;
158			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = (probeAngle + 5) % 360;
159			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = (probeAngle + 355) % 360;
160			else h = false;
161			if (h) e.preventDefault();
162		}
163	
164		function lengthKeys(e: KeyboardEvent) {
165			let h = true;
166			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
167			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
168			else h = false;
169			if (h) e.preventDefault();
170		}
171	
172		const f = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(2);
173		const cl = (v: number) => Math.min(Math.max(v, 24), S - 24);
174	
175		// Bar scale: scores live in [-2, 2] once c1 can stretch.
176		const BARMAX = 2.05;
177		const barH = 96;
178		const segH = (v: number) => (Math.abs(v) / BARMAX) * (barH / 2);
179	
180		const probeTip = $derived(pt(probe.x, probe.y));
181		const c1row = $derived(rows[0]);
182		const c1HandlePos = $derived(pt(c1row.x, c1row.y));
183		// The probe's own tip label: offset 13deg tangentially (never a multiple
184		// of 5, so it can never land on a candidate's angle, which are all
185		// multiples of 10) plus extra radial pad, so "probe" never sits on top
186		// of a candidate arrow or its tip label even when the probe points
187		// straight at one.
188		const probeLabelPos = $derived(labelPos(probeAngle + 13, 1, 34));
189	</script>
190	
191	<svelte:window onpointerup={() => (dragging = null)} />
192	
193	<div class="lab" data-interactive="dot-alignment">
194		<p class="invite">
195			Every song here is two numbers: how <em class="qw-loud">loud</em>, how <em class="qw-fast">fast</em>. So is your taste. Turn
196			the amber taste arrow and watch each song's match get <em>built</em>: the <span class="qw-loud">loud product</span> plus
197			the <span class="qw-fast">fast product</span>, stacked into one bar. Then grab Night Drive's round handle and change its size.
198		</p>
199		<div class="challenges">
200			<button class="chal" class:active={challenge === 'cheat' && !solvedCheat} class:done={solvedCheat} onclick={() => startChallenge('cheat')}>
201				<span class="chal-t mono">challenge 01</span>
202				<span class="chal-g">Make a worse match win</span>
203				{#if solvedCheat}
204					<span class="chal-s mono">✓ solved · click to retry</span>
205					<span class="chal-why">{WHY.cheat}</span>
206				{:else if challenge === 'cheat'}
207					<span class="chal-s mono live">in play…</span>
208				{/if}
209			</button>
210			<button class="chal" class:active={challenge === 'short' && !solvedShort} class:done={solvedShort} onclick={() => startChallenge('short')}>
211				<span class="chal-t mono">challenge 02</span>
212				<span class="chal-g">Make the truest song lose</span>
213				{#if solvedShort}
214					<span class="chal-s mono">✓ solved · click to retry</span>
215					<span class="chal-why">{WHY.short}</span>
216				{:else if challenge === 'short'}
217					<span class="chal-s mono live">in play…</span>
218				{/if}
219			</button>
220		</div>
221	
222		<div class="stage">
223			<div class="arena-wrap">
224				<svg
225					bind:this={arenaEl}
226					viewBox="0 0 {S} {S}"
227					class="arena"
228					onpointermove={onArenaPointer}
229					role="img"
230					aria-label="An amber probe arrow among four periwinkle candidate arrows; drag the probe tip to turn it, drag c1's tip to stretch it"
231				>
232					<!-- angle ring + ticks -->
233					<circle cx={CX} cy={CY} r={R} class="ring" />
234					{#each Array.from({ length: 12 }, (_, i) => i * 30) as t (t)}
235						<line
236							x1={CX + (R - 4) * Math.cos(rad(t))}
237							y1={CY - (R - 4) * Math.sin(rad(t))}
238							x2={CX + (R + 4) * Math.cos(rad(t))}
239							y2={CY - (R + 4) * Math.sin(rad(t))}
240							class="tick"
241						/>
242					{/each}
243					<!-- axes, whisper-quiet, but named: the two entries ARE qualities -->
244					<line x1={CX - R - 14} y1={CY} x2={CX + R + 14} y2={CY} class="axis" />
245					<line x1={CX} y1={CY - R - 14} x2={CX} y2={CY + R + 14} class="axis" />
246					<text x={CX + R + 18} y={CY - 6} class="axisq q-loud mono" aria-hidden="true">loud</text>
247					<text x={CX - 10} y={CY - R - 8} text-anchor="end" class="axisq q-fast mono" aria-hidden="true">fast</text>
248					<g class="legend" aria-hidden="true">
249						<line x1="16" y1="20" x2="34" y2="20" class="lg probe-stroke" />
250						<text x="40" y="24" class="lgt mono">your taste</text>
251						<line x1="16" y1="38" x2="34" y2="38" class="lg cand-stroke" />
252						<text x="40" y="42" class="lgt mono">songs</text>
253					</g>
254	
255					<!-- coordinates made visible: dashed drops for probe and selected -->
256					{#each [{ x: probe.x, y: probe.y, cls: 'p' }, { x: sel.x, y: sel.y, cls: 'c' }] as d (d.cls)}
257						{@const tip = pt(d.x, d.y)}
258						<line x1={tip.px} y1={tip.py} x2={tip.px} y2={CY} class="drop {d.cls}" />
259						<line x1={tip.px} y1={tip.py} x2={CX} y2={tip.py} class="drop {d.cls}" />
260						<text x={cl(tip.px)} y={CY + (d.cls === 'p' ? 13 : 25)} class="coord mono {d.cls}" aria-hidden="true">{f(d.x)}</text>
261						<text x={CX - (d.cls === 'p' ? 4 : 32)} y={cl(tip.py) - 3} class="coord mono {d.cls}" text-anchor="end" aria-hidden="true">{f(d.y)}</text>
262					{/each}
263	
264					<!-- candidates: each carries its name at its tip, always, nudged
265					     radially clear of the ring so the sweeping probe never buries
266					     it (the probe's own label uses a different angle offset so
267					     it can never land in the same spot). -->
268					{#each rows as r (r.id)}
269						{@const a = arrow(r.x, r.y)}
270						{@const lp = labelPos(r.angle, r.len, 26)}
271						<g
272							class="cand"
273							class:sel={selected === r.id}
274							class:hov={hovered === r.id}
275							onpointerdown={() => (selected = r.id)}
276							role="button"
277							tabindex="-1"
278							aria-label={`select ${r.name}`}
279						>
280							<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft cand-stroke" />
281							<polygon points={a.head} class="cand-fill" />
282							<text
283								x={Math.min(Math.max(lp.px, 44), S - 48)}
284								y={Math.min(Math.max(lp.py, 16), S - 10)}
285								class="lab song-lab halo"
286								class:sel-lab={selected === r.id}
287								aria-hidden="true">{r.name}</text>
288						</g>
289					{/each}
290	
291					<!-- probe on top -->
292					{#if true}
293						{@const a = arrow(probe.x, probe.y)}
294						<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft probe-stroke" />
295						<polygon points={a.head} class="probe-fill" />
296					{/if}
297					<text
298						x={Math.min(Math.max(probeLabelPos.px, 44), S - 48)}
299						y={Math.min(Math.max(probeLabelPos.py, 16), S - 10)}
300						class="lab song-lab probe-lab-text halo"
301						aria-hidden="true">probe</text>
302					<circle
303						cx={probeTip.px}
304						cy={probeTip.py}
305						r="22"
306						onpointermove={onArenaPointer}
307						class="handle probe-handle"
308						class:active={dragging === 'probe'}
309						onpointerdown={(e) => startDrag('probe', e)}
310						onkeydown={probeKeys}
311						role="slider"
312						tabindex="0"
313						aria-label="probe angle in degrees"
314						aria-valuemin="0"
315						aria-valuemax="360"
316						aria-valuenow={Math.round(probeAngle)}
317					/>
318					<!-- Night Drive's length handle. AFTER the probe handle on purpose:
319					     the primary angle slider must be the FIRST [role="slider"] in
320					     the DOM (the drive contract grabs the first one). -->
321					<circle
322						cx={c1HandlePos.px}
323						cy={c1HandlePos.py}
324						r="22"
325						onpointermove={onArenaPointer}
326						class="handle length-handle"
327						class:active={dragging === 'length'}
328						class:pulse={challenge !== null && !((challenge === 'cheat' && cheatActive) || (challenge === 'short' && shortChanged))}
329						onpointerdown={(e) => startDrag('length', e)}
330						onkeydown={lengthKeys}
331						role="slider"
332						tabindex="0"
333						data-control="length-c1"
334						aria-label="c1 length"
335						aria-valuemin="0.5"
336						aria-valuemax="2"
337						aria-valuenow={f1(lengthC1)}
338					/>
339					<text x="14" y={S - 14} class="angle mono" aria-hidden="true">taste at {Math.round(probeAngle)}°</text>
340				</svg>
341			</div>
342	
343			<div class="meter">
344				{#each rows as r (r.id)}
345					<button
346						class="row"
347						class:leading={leaders.includes(r.id) && !tied}
348						class:sel={selected === r.id}
349						onmouseenter={() => (hovered = r.id)}
350						onmouseleave={() => (hovered = null)}
351						onclick={() => (selected = r.id)}
352						aria-label={`${r.id} score ${f1(r.score)}${leaders.includes(r.id) && !tied ? ', leading' : ''}`}
353					>
354						<span class="row-id">{r.name}</span>
355						<span class="bar" style="--h: {barH}px">
356							<span class="zero"></span>
357							<!-- x-term segment then y-term segment, stacked from the baseline -->
358							<span
359								class="seg segx"
360								class:neg={r.px < 0}
361								style="height: {segH(r.px)}px; bottom: {r.px >= 0 ? barH / 2 : barH / 2 - segH(r.px)}px"
362							></span>
363							<span
364								class="seg segy"
365								class:neg={r.py < 0}
366								style="height: {segH(r.py)}px; bottom: {r.py >= 0
367									? barH / 2 + (r.px > 0 ? segH(r.px) : 0)
368									: barH / 2 - segH(r.py) - (r.px < 0 ? segH(r.px) : 0)}px"
369							></span>
370						</span>
371						<span class="row-score mono" class:neg={r.score < 0}>{f1(r.score)}</span>
372						{#if leaders.includes(r.id) && !tied}<span class="leads mono">leads</span>{/if}
373					</button>
374				{/each}
375				{#if tied}<span class="tie mono">tied</span>{/if}
376				{#if cheatVictim}
377					<span class="flag mono">⚑ {cheatVictim.name} matches your taste better, but Night Drive outscores it on size</span>
378				{:else if shortChanged}
379					<span class="flag short mono">⚑ Night Drive matches best, but {leaderName} wins on size</span>
380				{/if}
381			</div>
382		</div>
383		{#if challenge === null && cheatActive}
384			<p class="why">Why this matters: {WHY.cheat}</p>
385		{:else if challenge === null && shortChanged}
386			<p class="why">Why this matters: {WHY.short}</p>
387		{/if}
388		<p class="hint">
389			Click any bar or arrow to inspect it. The dashed lines are that arrow's two
390			entries (its loudness and its speed), the numbers the recipe multiplies.
391		</p>
392	
393		<div class="strip" aria-live="polite">
394			<span class="strip-lead">the whole recipe, live for <b>{sel.name}</b>:</span>
395			<span class="mono eq">
396				<span class="op qw-loud">loud</span>
397				<span class="probe-c">{f(probe.x)}</span>·<span class="cand-c">{f(sel.x)}</span>
398				<span class="op">+</span>
399				<span class="op qw-fast">fast</span>
400				<span class="probe-c">{f(probe.y)}</span>·<span class="cand-c">{f(sel.y)}</span>
401				<span class="op">=</span>
402				<span class="segx-c">{f(sel.px)}</span>
403				<span class="op">+</span>
404				<span class="segy-c">{f(sel.py)}</span>
405				<span class="op">=</span>
406				<span class="score-c">{f1(sel.score)}</span>
407			</span>
408			<span class="strip-note">
409				multiply the matched entries, add the products. The <span class="qw-loud">lilac slice</span>
410				of each bar is its loud product, the <span class="qw-fast">mint slice</span> its fast
411				product; stacked, they are the score.
412			</span>
413		</div>
414	</div>
415	
416	<style>
417		.lab {
418			max-width: 860px;
419			margin: 2rem auto;
420			padding: 1.4rem 1.6rem 1.2rem;
421			background: var(--color-surface);
422			border: 1px solid color-mix(in oklab, var(--color-text) 8%, transparent);
423			border-radius: 14px;
424		}
425		.invite {
426			margin: 0 0 1rem;
427			font-size: 0.98rem;
428			line-height: 1.5;
429			color: color-mix(in oklab, var(--color-text) 88%, transparent);
430		}
431		.invite em { color: var(--color-brand-mint); font-style: normal; }
432		.invite .qw-loud, .lab .invite .qw-loud { color: var(--data-params); font-style: normal; }
433		.invite .qw-fast, .lab .invite .qw-fast { color: color-mix(in oklab, var(--color-brand-mint) 85%, var(--color-text)); font-style: normal; }
434		.mono { font-family: var(--font-mono); }
435	
436		.stage { display: flex; flex-direction: column; gap: 0.8rem; align-items: center; }
437		.arena-wrap { width: 100%; max-width: 620px; }
438		.arena { width: 100%; height: auto; touch-action: none; display: block; }
439	
440		.ring { fill: none; stroke: color-mix(in oklab, var(--color-text) 10%, transparent); stroke-width: 1; }
441		.tick { stroke: color-mix(in oklab, var(--color-text) 14%, transparent); stroke-width: 1; }
442		.axis { stroke: color-mix(in oklab, var(--color-text) 7%, transparent); stroke-width: 1; }
443	
444		.shaft { stroke-width: 2.4; stroke-linecap: round; }
445		.cand-stroke { stroke: var(--data-observed); }
446		.cand-fill { fill: var(--data-observed); }
